content:
{
  "sentences": [
    {
      "text": "請你把那本書拿來給我。",
      "pinyin": "Qǐng nǐ bǎ nà běn shū ná lái gěi wǒ.",
      "pinyin_numeric": "qing3 ni3 ba3 na4 ben3 shu1 na2 lai2 gei3 wo3",
      "translation_en": "Please bring that book to me.",
      "translation_ko": "그 책을 저에게 가져와 주세요."
    },
    {
      "text": "他把手機拿去了公司。",
      "pinyin": "Tā bǎ shǒujī ná qù le gōngsī.",
      "pinyin_numeric": "ta1 ba3 shou3ji1 na2 qu4 le gong1si1",
      "translation_en": "He took his phone to the company.",
      "translation_ko": "그는 핸드폰을 회사로 가져갔어요."
    },
    {
      "text": "我已經把咖啡拿來了。",
      "pinyin": "Wǒ yǐjīng bǎ kāfēi ná lái le.",
      "pinyin_numeric": "wo3 yi3jing1 ba3 ka1fei1 na2 lai2 le",
      "translation_en": "I have already brought the coffee.",
      "translation_ko": "저는 이미 커피를 가져왔어요."
    },
    {
      "text": "請你把這杯水拿去給媽媽。",
      "pinyin": "Qǐng nǐ bǎ zhè bēi shuǐ ná qù gěi māma.",
      "pinyin_numeric": "qing3 ni3 ba3 zhe4 bei1 shui3 na2 qu4 gei3 ma1ma",
      "translation_en": "Please take this glass of water to Mom.",
      "translation_ko": "이 물 한 잔을 엄마에게 가져다 주세요."
    },
    {
      "text": "他把我的書拿去了圖書館。",
      "pinyin": "Tā bǎ wǒ de shū ná qù le túshūguǎn.",
      "pinyin_numeric": "ta1 ba3 wo3 de shu1 na2 qu4 le tu2shu1guan3",
      "translation_en": "He took my book to the library.",
      "translation_ko": "그는 제 책을 도서관으로 가져갔어요."
    },
    {
      "text": "你幫我把這個袋子拿來好嗎？",
      "pinyin": "Nǐ bāng wǒ bǎ zhège dàizi ná lái hǎo ma?",
      "pinyin_numeric": "ni3 bang1 wo3 ba3 zhe4ge dai4zi na2 lai2 hao3 ma0",
      "translation_en": "Can you bring this bag for me?",
      "translation_ko": "이 가방을 저를 위해 가져와 주시겠어요?"
    },
    {
      "text": "他已經把便當拿來了。",
      "pinyin": "Tā yǐjīng bǎ biàndāng ná lái le.",
      "pinyin_numeric": "ta1 yi3jing1 ba3 bian4dang1 na2 lai2 le",
      "translation_en": "He has already brought the lunch box.",
      "translation_ko": "그는 이미 도시락을 가져왔어요."
    },
    {
      "text": "請你把這份菜單拿去給客人。",
      "pinyin": "Qǐng nǐ bǎ zhè fèn càidān ná qù gěi kèrén.",
      "pinyin_numeric": "qing3 ni3 ba3 zhe4 fen4 cai4dan1 na2 qu4 gei3 ke4ren2",
      "translation_en": "Please take this menu to the customer.",
      "translation_ko": "이 메뉴판을 손님에게 가져다 주세요."
    },
    {
      "text": "我把雨傘拿來了。",
      "pinyin": "Wǒ bǎ yǔsǎn ná lái le.",
      "pinyin_numeric": "wo3 ba3 yu3san3 na2 lai2 le",
      "translation_en": "I brought the umbrella.",
      "translation_ko": "저는 우산을 가져왔어요."
    },
    {
      "text": "他把我的手機拿去了。",
      "pinyin": "Tā bǎ wǒ de shǒujī ná qù le.",
      "pinyin_numeric": "ta1 ba3 wo3 de shou3ji1 na2 qu4 le",
      "translation_en": "He took my phone away.",
      "translation_ko": "그는 제 핸드폰을 가져갔어요."
    }
  ]
}
